using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // EF Core 9 changed the default id format from "EntityType|Key" to just "Key".
        // Existing 500K documents use "Product|123" format, so we must opt in to the old behavior.
        optionsBuilder.UseCosmos(/* connection params */)
            ;
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1 — Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents and raw SQL queries use "Discriminator", so preserve it.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2 — Id format changed from "EntityType|Key" to just "Key".
            // Existing documents have ids like "Product|123", so preserve the old format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

